const item = $input.first().json;

const ethicalKeywords = [
  'gender perspective',
  'cultural diversity',
  'accessibility',
  'universal design',
  'sustainability',
  'community safety',
  'social cohesion'
];

const participationSummary = `
Issue: ${item.issue_main}
Affected groups: ${item.affected_groups?.join(", ")}
When: ${item.issue_timing?.join(", ")}
Severity: ${item.issue_severity}
Causes: ${item.issue_causes}
Attempts: ${item.issue_attempts}
Red lines: ${item.issue_red_lines}
`;

const valuesSummary = `
Priority values: ${item.priority_values?.join(", ")}
Fair solution: ${item.fair_solution_definition}
Ignored groups: ${item.ignored_groups?.join(", ")}
Ethical principles: ${item.ethical_principles?.join(", ")}
Non negotiables: ${item.non_negotiables}
`;

return [{
  json: {
    ...item,

    ethicalKeywords,

    citizen_profile: {
      area: item.area,
      connection: item.area_connection,
      frequency: item.area_frequency,
      priorities: item.priority_values,
      lived_experience: item.issue_main
    },

    llm_input: {
      area: item.area,
      issue: item.issue_main,
      participation_summary: participationSummary,
      values_summary: valuesSummary,
      ethical_keywords: ethicalKeywords,
      desired_solutions: item.solution_types,
      community_assets: item.community_assets
    }
  }
}];

const proposals = $('AI Agent - Generate Proposals').first().json.output.proposals || [];
const ethical = $('AI Agent - Ethical Review').first().json.output || {};
const scores = $('AI Agent  –  Impact Scoring').first().json.output.scores || [];
const buildQuery = $('Build Query').first().json || {};
const baseInput = $('Code in JavaScript').first().json || {};

function detectCategory(issue, solutionTypes = [], values = []) {
  const text = [
    issue || '',
    ...(solutionTypes || []),
    ...(values || []),
  ].join(' ').toLowerCase();

  if (/(housing|rent|eviction|home|homeless|habitat)/.test(text)) return 'Housing';
  if (/(green|tree|park|nature|heat|climate|sustainab)/.test(text)) return 'Environment';
  if (/(mobility|traffic|bike|bus|transport|walk|pedestrian|street)/.test(text)) return 'Mobility';
  if (/(safety|violence|crime|lighting|security)/.test(text)) return 'Safety';
  if (/(accessib|disab|inclusive|universal design)/.test(text)) return 'Accessibility';
  if (/(youth|school|education|learning|children)/.test(text)) return 'Education';
  if (/(health|care|mental|wellbeing)/.test(text)) return 'Health';
  if (/(community|participation|co-design|civic|social cohesion)/.test(text)) return 'Community';
  if (/(clean|waste|trash|noise|pollution)/.test(text)) return 'Public Space';
  return 'Other';
}

const issue = buildQuery.issue_main || null;
const area = buildQuery.area || null;
const participant = buildQuery.participant_name || null;
const priorityValues = buildQuery.priority_values || [];
const solutionTypes = baseInput.solution_types || [];
const category = detectCategory(issue, solutionTypes, priorityValues);

return [{
  json: {
    created_at: new Date().toISOString(),

    issue,
    area,
    participant,

    // add fields for dashboard grouping/filtering
    category,
    main_topic: category,
    priority_values: priorityValues,
    solution_types: solutionTypes,

    proposals,
    scores,

    proposal_count: proposals.length,

    approved: ethical.approved ?? null,
    ethical_issues: ethical.issues || [],
    ethical_issues_count: ethical.issues?.length || 0,

    status: ethical.approved ? 'approved' : 'needs_revision',
  }
}];

const inputJson = $input.first().json || {};
const body = inputJson.body ?? {};
const source = inputJson.data ?? inputJson;

const norm = (s) =>
  String(s ?? '')
    .trim()
    .toLowerCase()
    .replace(/\s+/g, ' ');

const valueKeys = [
  'value',
  'answer',
  'answers',
  'text',
  'selected',
  'selection',
  'choices',
  'choice',
  'option',
  'options',
  'response',
];

function extractCandidateValue(obj) {
  for (const key of valueKeys) {
    if (obj && Object.prototype.hasOwnProperty.call(obj, key)) {
      return obj[key];
    }
  }
  return undefined;
}

function findByLabels(root, labels) {
  const wanted = labels.map(norm);
  const seen = new Set();

  function walk(node) {
    if (node === null || node === undefined) return undefined;
    if (typeof node !== 'object') return undefined;
    if (seen.has(node)) return undefined;
    seen.add(node);

    if (Array.isArray(node)) {
      for (const item of node) {
        const result = walk(item);
        if (result !== undefined) return result;
      }
      return undefined;
    }

    for (const [key, value] of Object.entries(node)) {
      if (wanted.includes(norm(key))) return value;
    }

    for (const descriptor of ['label', 'title', 'question', 'name', 'key']) {
      if (node[descriptor] !== undefined && wanted.includes(norm(node[descriptor]))) {
        const candidate = extractCandidateValue(node);
        if (candidate !== undefined) return candidate;
      }
    }

    for (const value of Object.values(node)) {
      const result = walk(value);
      if (result !== undefined) return result;
    }

    return undefined;
  }

  const result = walk(root);
  return result === undefined ? null : result;
}

function asArray(value) {
  if (Array.isArray(value)) return value;
  if (value === null || value === undefined || value === '') return [];
  return [value];
}

function asNumber(value) {
  if (value === null || value === undefined || value === '') return null;
  const n = Number(value);
  return Number.isFinite(n) ? n : null;
}

const isDashboardTrigger =
  inputJson.source === 'dashboard_manual_trigger' ||
  body.source === 'dashboard_manual_trigger' ||
  source.source === 'dashboard_manual_trigger' ||
  source.hidden?.source === 'dashboard_manual_trigger';

const normalized = {
  consent_given:
    source.consent_given ??
    Boolean(
      findByLabels(source, [
        'Before continuing, please confirm:',
        'I understand that my answers may be processed by AI to help generate community proposals.'
      ])
    ),

  project_id: source.project_id ?? source.hidden?.project_id ?? null,
  pilot_topic: source.pilot_topic ?? source.hidden?.pilot_topic ?? null,
  session_id: source.session_id ?? source.hidden?.session_id ?? null,
  facilitator: source.facilitator ?? source.hidden?.facilitator ?? null,
  language: source.language ?? source.hidden?.language ?? null,
  source: source.source ?? source.hidden?.source ?? null,
  workshop_id: source.workshop_id ?? source.hidden?.workshop_id ?? null,

  participant_name: findByLabels(source, ['What should we call you?']),
  participant_email: findByLabels(source, ['Email (optional)']),

  area: findByLabels(source, ['Which neighborhood or area are you talking about?']),
  area_connection: findByLabels(source, ['What is your connection to this area?']),
  area_frequency: findByLabels(source, ['How often are you in this area?']),

  issue_main: findByLabels(source, [
    'What is the main issue or challenge in this neighborhood or public space?'
  ]),
  affected_groups: asArray(findByLabels(source, ['Who is most affected by this issue?'])),
  issue_timing: asArray(findByLabels(source, ['When does this issue happen most often?'])),
  issue_severity: asNumber(findByLabels(source, ['How serious is this issue for you?'])),
  issue_causes: findByLabels(source, ['What do you think is causing this issue?']),
  issue_attempts: findByLabels(source, ['Has anything already been tried to solve it?']),
  issue_red_lines: findByLabels(source, [
    'What should definitely not happen in any future solution?'
  ]),

  priority_values: asArray(findByLabels(source, [
    'Which values should be prioritized most in this area? Choose up to 3.',
    'Which values should be prioritized most in this area?'
  ])),

  fair_solution_definition: findByLabels(source, ['What would a fair solution look like here?']),
  ignored_groups: asArray(findByLabels(source, [
    'Which groups are often ignored in decisions like this?'
  ])),
  ethical_principles: asArray(findByLabels(source, [
    'Which principles should always be respected in any proposal?'
  ])),
  non_negotiables: findByLabels(source, [
    'Are there any values or principles that should never be compromised?'
  ]),

  solution_types: asArray(findByLabels(source, [
    'What kinds of solutions would you like to see? Choose all that apply.',
    'What kinds of solutions would you like to see?'
  ])),

  best_first_step: findByLabels(source, ['What would be the best first step?']),
  community_assets: findByLabels(source, [
    'What resources, strengths, or community assets already exist here?'
  ]),
  solution_stakeholders: asArray(findByLabels(source, [
    'Who should be involved in designing or implementing a solution?'
  ])),
  success_6m: findByLabels(source, ['What would a successful outcome look like in 6 months?']),
  future_workshop_interest: findByLabels(source, [
    'Would you like to take part in a future workshop or co-design session?'
  ]),
  final_comment: findByLabels(source, [
    'Is there anything else you want us to understand before generating proposals?'
  ]),

  _raw: source,
};

console.log('INPUT DATA:', JSON.stringify(inputJson, null, 2));
console.log('NORMALIZED SOURCE:', JSON.stringify(source, null, 2));
console.log('isDashboardTrigger:', isDashboardTrigger);
console.log('NORMALIZED OUTPUT:', JSON.stringify(normalized, null, 2));

if (!normalized.consent_given && !isDashboardTrigger) {
  throw new Error('Consent not given');
}

if (isDashboardTrigger) {
  normalized.consent_given = source.consent_given ?? true;
}

return [{ json: normalized }];

const item = $input.item;

if (!item.binary) {
  throw new Error('No binary file found');
}

const key = Object.keys(item.binary)[0];
item.binary[key].mimeType = 'application/pdf';
item.binary[key].fileName = 'faq.pdf';

// Preserve title and url from input
item.json.title = item.json.title;
item.json.url = item.json.url;

return item;

const issue = $json.issue_main || "lack of green spaces";
const area = $json.area || "Gràcia";
const values = ($json.priority_values?.length ? $json.priority_values : ["sustainability","community"]).join(", ");

const query = `
Urban planning regulations, civic participation frameworks, and policy guidance related to:

Issue: ${issue}
Location: ${area}
Community priorities: ${values}

Focus on technical solutions, urban policy, planning guidelines, and governance practices.
`;

return [{
  json: {
    ...$json,

    // overwrite null fields with working defaults
    issue_main: issue,
    area: area,
    priority_values: values.split(", "),

    query: query
  }
}];

const base = $json;

// Try to extract documents from different possible shapes
const docs =
  base.documents ||
  base.results ||
  base.matches ||
  base.data ||
  [];

// Extract text from documents if they exist
let text = docs
  .map(d => d.pageContent || d.content || d.text || d.metadata?.text || "")
  .filter(Boolean)
  .join("\n\n");

// If the AI Agent returned text instead of docs, use that
if (!text && base.output) {
  text = base.output;
}

return [
  {
    json: {
      // Keep only essential fields from input, NOT the raw output
      project_id: base.project_id,
      query: base.query,

      // Single consolidated context field
      context: text || "No technical documents found",

      // Metadata only
      doc_count: docs.length || (base.output ? 1 : 0),
      context_length: text.length
    }
  }
];
